VALUES
  ('judicial-f0899a01-moex-00546', 'judicial-f0899a01', 'judicial-f0899a01-moex-110-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '關於信賴保護補償之敘述，下列何者錯誤？', '["甲明知其所有之土地不得建築房屋，雖主管機關違法核發其建築執照，甲既已進行施工，仍可請求損失 之補償", "信賴保護之補償範圍不包括人民之所失利益", "行政機關對於人民信賴行政處分之信賴保護補償額度，不得超過受益人因該處分存續可得之利益", "人民對於信賴保護補償之金額，如有不服，得向行政法院提起給付訴訟"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:48+00:00", "source_pdf_sha1": "ff136e5557ae", "answer_pdf_sha1": "c9b885251cb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "203", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00547', 'judicial-f0899a01', 'judicial-f0899a01-moex-110-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '有關行政機關之判斷餘地，下列敘述何者錯誤？', '["國家考試閱卷委員對於考試成績的評定享有判斷餘地", "長官對於所屬公務員年終考績之評定有判斷餘地", "環境影響評估審查結論之作成有判斷餘地", "上級機關訂定裁量基準之行為有判斷餘地"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:48+00:00", "source_pdf_sha1": "ff136e5557ae", "answer_pdf_sha1": "c9b885251cb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "203", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00548', 'judicial-f0899a01', 'judicial-f0899a01-moex-110-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '下列何者非屬私經濟行政？', '["國家提供大學生低利率助學貸款", "行政院農業委員會為平抑菜價出售大宗特定農產品", "行政機關與清潔公司訂立清掃辦公大樓之承攬契約", "對申請提供政府資訊之人民收取複製該資訊之費用"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:48+00:00", "source_pdf_sha1": "ff136e5557ae", "answer_pdf_sha1": "c9b885251cb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "203", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00549', 'judicial-f0899a01', 'judicial-f0899a01-moex-110-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '關於公法上之消滅時效制度，下列敘述何者錯誤？', '["行政機關對於行政契約之終止權，因5年間不行使而消滅", "公法上消滅時效制度採權利消滅主義，與民法上消滅時效之法律效果不同", "行政機關對於人民享有請求權，如作成實現該請求權之行政處分，則時效中斷", "人民與行政機關間處於資訊的不對等關係，故人民對於行政機關請求權之消滅時效期間較長"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:48+00:00", "source_pdf_sha1": "ff136e5557ae", "answer_pdf_sha1": "c9b885251cb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "203", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00550', 'judicial-f0899a01', 'judicial-f0899a01-moex-110-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '依中央行政機關組織基準法之規定，機關組織業務相同而轄區不同或權限相同而管轄事務不同之機關，其 共同適用之組織法律定名為：', '["條例", "細則", "準則", "通則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:48+00:00", "source_pdf_sha1": "ff136e5557ae", "answer_pdf_sha1": "c9b885251cb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "203", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00551', 'judicial-f0899a01', 'judicial-f0899a01-moex-110-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '關於行政命令作為行政法之法源，下列敘述何者正確？', '["有效下達之行政規則，具有拘束下級機關之效力", "法規命令不得作為行政法之法源", "應適用法律保留原則之事項，行政規則亦得成為行政法之法源", "行政規則皆須對外公布始得成為行政法之法源"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:48+00:00", "source_pdf_sha1": "ff136e5557ae", "answer_pdf_sha1": "c9b885251cb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "203", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00552', 'judicial-f0899a01', 'judicial-f0899a01-moex-110-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '關於行政機關管轄權爭議之處理，下列敘述何者正確？', '["由該數行政機關自行協調出一個機關管轄", "由提出爭議方之行政機關之上級機關決定之", "由其共同上級機關決定之", "統一由行政院指定管轄"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:48+00:00", "source_pdf_sha1": "ff136e5557ae", "answer_pdf_sha1": "c9b885251cb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "203", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00553', 'judicial-f0899a01', 'judicial-f0899a01-moex-110-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '依行政程序法規定，下列何者非屬行政機關得請求其他機關協助之情形？', '["因法律上之原因，不能獨自執行職務", "因人員、設備不足等事實上之原因，不能獨自執行職務", "基於增加彼此機關人員之職務歷練", "由被請求機關協助執行，顯較經濟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:48+00:00", "source_pdf_sha1": "ff136e5557ae", "answer_pdf_sha1": "c9b885251cb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "203", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00554', 'judicial-f0899a01', 'judicial-f0899a01-moex-110-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '依公務人員考績法之規定，下列敘述何者錯誤？', '["年終考績係指各官等人員，於每年年終考核其當年1月至12月任職期間之成績", "受考人在考績年度內，如有怠忽職守、稽延公務、造成重大不良後果且有確實證據者，得考列丁等", "專案考績係指各官等人員於同一考績年度內，任職不滿1年，而連續任職已達6個月者辦理之考績", "考績委員會對於擬予考績列丁等之人員，處分前應給予當事人陳述及申辯之機會"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:48+00:00", "source_pdf_sha1": "ff136e5557ae", "answer_pdf_sha1": "c9b885251cb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "203", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00555', 'judicial-f0899a01', 'judicial-f0899a01-moex-110-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '依司法院大法官解釋意旨，下列敘述何者錯誤？', '["立法委員不得兼任公營事業機關之董事、監察人及總經理", "公立學校兼任行政職務之教師，就其兼任之行政職務，有公務員服務法之適用", "公營事業機關代表民股之董事，不論是否受有俸給，均有公務員服務法之適用", "適用公務員服務法之公務員，除法令另有規定者外，不得兼任私立學校之董事長或董事"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:48+00:00", "source_pdf_sha1": "ff136e5557ae", "answer_pdf_sha1": "c9b885251cb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "203", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL)
